10	library ieee;
11	use ieee.std_logic_1164.all;
12	use ieee.numeric_std.all;
13	
14	library work;
15	use work.psi_common_math_pkg.all;
16	use work.psi_common_array_pkg.all;
17	use work.psi_common_logic_pkg.all;
18	use work.psi_ms_daq_pkg.all;
19	
20	------------------------------------------------------------------------------
21	-- Entity Declaration
22	------------------------------------------------------------------------------
23	entity psi_ms_daq_reg_axi is
24	  generic(
25	    Streams_g         : integer range 1 to 32;
26	    MaxWindows_g      : integer range 1 to 32;
27	    AxiSlaveIdWidth_g : integer
28	  );
29	  port(
30	    -- AXI Control Signals
31	    S_Axi_Aclk    : in  std_logic;
32	    S_Axi_Aresetn : in  std_logic;
33	    -- AXI Read address channel
34	    S_Axi_ArId    : in  std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
35	    S_Axi_ArAddr  : in  std_logic_vector(15 downto 0);
36	    S_Axi_Arlen   : in  std_logic_vector(7 downto 0);
37	    S_Axi_ArSize  : in  std_logic_vector(2 downto 0);
38	    S_Axi_ArBurst : in  std_logic_vector(1 downto 0);
39	    S_Axi_ArLock  : in  std_logic;
40	    S_Axi_ArCache : in  std_logic_vector(3 downto 0);
41	    S_Axi_ArProt  : in  std_logic_vector(2 downto 0);
42	    S_Axi_ArValid : in  std_logic;
43	    S_Axi_ArReady : out std_logic;
44	    -- AXI Read data channel
45	    S_Axi_RId     : out std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
46	    S_Axi_RData   : out std_logic_vector(31 downto 0);
47	    S_Axi_RResp   : out std_logic_vector(1 downto 0);
48	    S_Axi_RLast   : out std_logic;
49	    S_Axi_RValid  : out std_logic;
50	    S_Axi_RReady  : in  std_logic;
51	    -- AXI Write address channel
52	    S_Axi_AwId    : in  std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
53	    S_Axi_AwAddr  : in  std_logic_vector(15 downto 0);
54	    S_Axi_AwLen   : in  std_logic_vector(7 downto 0);
55	    S_Axi_AwSize  : in  std_logic_vector(2 downto 0);
56	    S_Axi_AwBurst : in  std_logic_vector(1 downto 0);
57	    S_Axi_AwLock  : in  std_logic;
58	    S_Axi_AwCache : in  std_logic_vector(3 downto 0);
59	    S_Axi_AwProt  : in  std_logic_vector(2 downto 0);
60	    S_Axi_AwValid : in  std_logic;
61	    S_Axi_AwReady : out std_logic;
62	    -- AXI Write data channel
63	    S_Axi_WData   : in  std_logic_vector(31 downto 0);
64	    S_Axi_WStrb   : in  std_logic_vector(3 downto 0);
65	    S_Axi_WLast   : in  std_logic;
66	    S_Axi_WValid  : in  std_logic;
67	    S_Axi_WReady  : out std_logic;
68	    -- AXI Write response channel
69	    S_Axi_BId     : out std_logic_vector(AxiSlaveIdWidth_g - 1 downto 0);
70	    S_Axi_BResp   : out std_logic_vector(1 downto 0);
71	    S_Axi_BValid  : out std_logic;
72	    S_Axi_BReady  : in  std_logic;
73	    -- Control Signals (AXI-S Clk)
74	    Arm           : out std_logic_vector(Streams_g - 1 downto 0);
75	    IsArmed       : in  std_logic_vector(Streams_g - 1 downto 0);
76	    IsRecording   : in  std_logic_vector(Streams_g - 1 downto 0);
77	    PostTrig      : out t_aslv32(Streams_g - 1 downto 0);
78	    RecMode       : out t_aslv2(Streams_g - 1 downto 0);
79	    ToDisable     : out std_logic_vector(Streams_g - 1 downto 0);
80	    FrameTo       : out std_logic_vector(Streams_g - 1 downto 0);
81	    IrqOut        : out std_logic;
82	    AWCache       : out std_logic_vector(3 downto 0);
83	    AWProt        : out std_logic_vector(2 downto 0);
84	    ARCache       : out std_logic_vector(3 downto 0);
85	    ARProt        : out std_logic_vector(2 downto 0);
86	    -- Memory Interfae Clock domain control singals
87	    ClkMem        : in  std_logic;
88	    RstMem        : in  std_logic;
89	    -- Context Memory Interface (MemClk)
90	    CtxStr_Cmd    : in  ToCtxStr_t;
91	    CtxStr_Resp   : out FromCtx_t;
92	    CtxWin_Cmd    : in  ToCtxWin_t;
93	    CtxWin_Resp   : out FromCtx_t;
94	    -- Logic Interface (MemClk)
95	    StrIrq        : in  std_logic_vector(Streams_g - 1 downto 0);
96	    StrLastWin    : in  WinType_a(Streams_g - 1 downto 0);
97	    StrEna        : out std_logic_vector(Streams_g - 1 downto 0);
98	    GlbEna        : out std_logic;
99	    InLevel       : in  t_aslv16(Streams_g - 1 downto 0)
100	  );
101	end entity;
102	
103	architecture rtl of psi_ms_daq_reg_axi is
104	  -- Two process method
105	  type two_process_r is record
106	    Reg_Gcfg_Ena       : std_logic;
107	    Reg_Gcfg_IrqEna    : std_logic;
108	    Reg_IrqVec         : std_logic_vector(Streams_g - 1 downto 0);
109	    Reg_IrqEna         : std_logic_vector(Streams_g - 1 downto 0);
110	    Reg_StrEna         : std_logic_vector(Streams_g - 1 downto 0);
111	    Reg_AcpCfg_ARProt  : std_logic_vector(2 downto 0);
112	    Reg_AcpCfg_ARCache : std_logic_vector(3 downto 0);
113	    Reg_AcpCfg_AWProt  : std_logic_vector(2 downto 0);
114	    Reg_AcpCfg_AWCache : std_logic_vector(3 downto 0);
115	    Reg_PostTrig       : t_aslv32(Streams_g - 1 downto 0);
116	    Reg_Mode_Recm      : t_aslv2(Streams_g - 1 downto 0);
117	    Reg_Mode_Arm       : std_logic_vector(Streams_g - 1 downto 0);
118	    Reg_Mode_ToDisable : std_logic_vector(Streams_g - 1 downto 0);
119	    Reg_Mode_FrameTo   : std_logic_vector(Streams_g - 1 downto 0);
120	    Irq                : std_logic;
121	    RegRdval           : std_logic_vector(31 downto 0);
122	    AddrReg            : std_logic_vector(15 downto 0);
123	    MaxLvlClr          : std_logic_vector(Streams_g - 1 downto 0);
124	  end record;
125	  signal r, r_next : two_process_r;
126	
127	  constant DwWrite_c : std_logic_vector(3 downto 0) := "1111";
128	
129	  constant DepthCtxStr_c    : integer := Streams_g * 32 / 8;
130	  constant CtxStrAddrHigh_c : integer := log2ceil(Streams_g * 32) - 1;
131	  signal CtxStr_WeLo        : std_logic;
132	  signal CtxStr_WeHi        : std_logic;
133	  signal CtxStr_Rdval       : std_logic_vector(63 downto 0);
134	  signal CtxStr_AddrB       : std_logic_vector(log2ceil(DepthCtxStr_c) - 1 downto 0);
135	  signal AddrCtxStr         : boolean;
136	
137	  constant DepthCtxWin_c    : integer := Streams_g * MaxWindows_g * 16 / 8;
138	  constant CtxWinAddrHigh_c : integer := log2ceil(Streams_g * MaxWindows_g * 16) - 1;
139	  signal CtxWin_WeLo        : std_logic;
140	  signal CtxWin_WeHi        : std_logic;
141	  signal CtxWin_Rdval       : std_logic_vector(63 downto 0);
142	  signal CtxWin_AddrB       : std_logic_vector(log2ceil(DepthCtxWin_c) - 1 downto 0);
143	  signal AddrCtxWin         : boolean;
144	
145	  -- High active reset
146	  signal A_Axi_Areset : std_logic;
147	
148	  -- Maximum Level Latching
149	  signal MaxLevel : t_aslv16(Streams_g - 1 downto 0);
150	
151	  -- Clock Crossing Signals
152	  signal StrIrq_Sync      : std_logic_vector(Streams_g - 1 downto 0);
153	  signal StrLastWin_Sync  : WinType_a(Streams_g - 1 downto 0);
154	  signal MaxLevel_Sync    : t_aslv16(Streams_g - 1 downto 0);
155	  signal MaxLevelClr_Sync : std_logic_vector(Streams_g - 1 downto 0);
156	
157	  -- Axi Accesses
158	  signal AccAddr     : std_logic_vector(15 downto 0);
159	  signal AccAddrOffs : std_logic_vector(15 downto 0);
160	  signal AccWr       : std_logic_vector(3 downto 0);
161	  signal AccWrData   : std_logic_vector(31 downto 0);
162	  signal AccRdData   : std_logic_vector(31 downto 0);
163	  signal RegWrVal    : t_aslv32(0 to 15);
164	  signal RegRdVal    : t_aslv32(0 to 15) := (others => (others => '0'));
165	  signal RegWr       : std_logic_vector(15 downto 0);
166	begin
167	  A_Axi_Areset <= not S_Axi_Aresetn;
168	
169	  --------------------------------------------
170	  -- Combinatorial Process
171	  --------------------------------------------
172	  p_comb : process(r, AccAddr, AccWr, AccWrData, StrIrq_Sync, IsArmed, IsRecording, CtxStr_Rdval, CtxWin_Rdval, MaxLevel, StrLastWin_Sync, RegWr, RegWrVal)
173	    variable v        : two_process_r;
174	    variable Stream_v : integer range 0 to Streams_g - 1;
175	  begin
176	    -- *** Hold variables stable ***
177	    v := r;
178	
179	    -- *** General Register Accesses ***
180	    -- GCFG
181	    if RegWr(16#00# / 4) = '1' then
182	      v.Reg_Gcfg_Ena    := RegWrVal(16#00# / 4)(0);
183	      v.Reg_Gcfg_IrqEna := RegWrVal(16#00# / 4)(8);
184	    end if;
185	    RegRdVal(16#00# / 4)(0) <= r.Reg_Gcfg_Ena;
186	    RegRdVal(16#00# / 4)(8) <= r.Reg_Gcfg_IrqEna;
187	
188	    -- GSTAT
189	    if RegWr(16#04# / 4) = '1' then
190	      null;
191	    end if;
192	    RegRdVal(16#04# / 4) <= (others => '0');
193	
194	    -- IRQVEC
195	    if RegWr(16#10# / 4) = '1' then
196	      v.Reg_IrqVec := r.Reg_IrqVec and (not RegWrVal(16#10# / 4)(Streams_g - 1 downto 0));
197	    end if;
198	    RegRdVal(16#10# / 4)(Streams_g - 1 downto 0) <= r.Reg_IrqVec;
199	
200	    -- IRQENA
201	    if RegWr(16#14# / 4) = '1' then
202	      v.Reg_IrqEna := RegWrVal(16#14# / 4)(Streams_g - 1 downto 0);
203	    end if;
204	    RegRdVal(16#14# / 4)(Streams_g - 1 downto 0) <= r.Reg_IrqEna;
205	
206	    -- STRENA
207	    if RegWr(16#20# / 4) = '1' then
208	      v.Reg_StrEna := RegWrVal(16#20# / 4)(Streams_g - 1 downto 0);
209	    end if;
210	    RegRdVal(16#20# / 4)(Streams_g - 1 downto 0) <= r.Reg_StrEna;
211	
212	    -- STRENA
213	    if RegWr(16#24# / 4) = '1' then
214	      v.Reg_AcpCfg_ARProt  := RegWrVal(16#24# / 4)( 2 downto  0);
215	      v.Reg_AcpCfg_ARCache := RegWrVal(16#24# / 4)( 7 downto  4);
216	      v.Reg_AcpCfg_AWProt  := RegWrVal(16#24# / 4)(10 downto  8);
217	      v.Reg_AcpCfg_AWCache := RegWrVal(16#24# / 4)(15 downto 12);
218	    end if;
219	    RegRdVal(16#24# / 4)( 2 downto  0) <= r.Reg_AcpCfg_ARProt;
220	    RegRdVal(16#24# / 4)( 7 downto  4) <= r.Reg_AcpCfg_ARCache;
221	    RegRdVal(16#24# / 4)(10 downto  8) <= r.Reg_AcpCfg_AWProt;
222	    RegRdVal(16#24# / 4)(15 downto 12) <= r.Reg_AcpCfg_AWCache;
223	
224	    -- *** Stream Register Accesses ***
225	    v.RegRdval     := (others => '0');
226	    v.Reg_Mode_Arm := (others => '0');
227	    v.MaxLvlClr    := (others => '0');
228	    if AccAddr(15 downto 9) = X"0" & "001" then
229	      Stream_v := work.psi_common_math_pkg.min(to_integer(unsigned(AccAddr(8 downto 4))), Streams_g - 1);
230	
231	      -- MAXLVLn
232	      if AccAddr(3 downto 0) = X"0" then
233	        if AccWr = DwWrite_c then
234	          v.MaxLvlClr(Stream_v) := '1';
235	        end if;
236	        v.RegRdval(15 downto 0) := MaxLevel(Stream_v);
237	      end if;
238	
239	      -- POSTTRIGn
240	      if AccAddr(3 downto 0) = X"4" then
241	        if AccWr = DwWrite_c then
242	          v.Reg_PostTrig(Stream_v) := AccWrData;
243	        end if;
244	        v.RegRdval := r.Reg_PostTrig(Stream_v);
245	      end if;
246	
247	      -- MODEn / LASTWINn
248	      if AccAddr(3 downto 0) = X"8" then
249	        if AccWr(0) = '1' then
250	          v.Reg_Mode_Recm(Stream_v) := AccWrData(1 downto 0);
251	        end if;
252	        if AccWr(1) = '1' then
253	          v.Reg_Mode_Arm(Stream_v) := AccWrData(8);
254	        end if;
255	        if AccWr(3) = '1' then
256	          v.Reg_Mode_ToDisable(Stream_v) := AccWrData(24);
257	          v.Reg_Mode_FrameTo(Stream_v)   := AccWrData(25);
258	        end if;
259	        v.RegRdval(1 downto 0) := r.Reg_Mode_Recm(Stream_v);
260	        v.RegRdval(8)          := IsArmed(Stream_v);
261	        v.RegRdval(16)         := IsRecording(Stream_v);
262	        v.RegRdval(24)         := r.Reg_Mode_ToDisable(Stream_v);
263	        v.RegRdval(25)         := r.Reg_Mode_FrameTo(Stream_v);
264	      end if;
265	
266	      -- LASTWINn
267	      if AccAddr(3 downto 0) = X"C" then
268	        -- LASTWINn
269	        v.RegRdval(MaxWindowsBits_c - 1 downto 0) := StrLastWin_Sync(Stream_v);
270	      end if;
271	
272	    end if;
273	
274	    -- *** Read Data MUX ***
275	    v.AddrReg := AccAddr;
276	    AccRdData <= (others => '0');
277	    if r.AddrReg(15 downto 12) = X"0" then
278	      AccRdData <= r.RegRdval;
279	    elsif r.AddrReg(15 downto 12) = X"1" then
280	      -- High-low dword in different memories
281	      if r.AddrReg(2) = '0' then
282	        AccRdData <= CtxStr_Rdval(31 downto 0);
283	      else
284	        AccRdData <= CtxStr_Rdval(63 downto 32);
285	      end if;
286	    elsif r.AddrReg(15 downto 14) = "01" then
287	      -- High-low dword in different memories
288	      if r.AddrReg(2) = '0' then
289	        AccRdData <= CtxWin_Rdval(31 downto 0);
290	      else
291	        AccRdData <= CtxWin_Rdval(63 downto 32);
292	      end if;
293	    end if;
294	
295	    -- *** IRQ Handling ***
296	    for i in 0 to Streams_g - 1 loop
297	      if (StrIrq_Sync(i) = '1') and (r.Reg_StrEna(i) = '1') then
298	        v.Reg_IrqVec(i) := '1';
299	      end if;
300	    end loop;
301	    if ((r.Reg_IrqVec and r.Reg_IrqEna) /= zeros_vector(Streams_g)) and (r.Reg_Gcfg_IrqEna = '1') then
302	      v.Irq := '1';
303	    else
304	      v.Irq := '0';
305	    end if;
306	
307	    -- *** Assign to signal ***
308	    r_next <= v;
309	
310	  end process;
311	
312	  -- *** Registered Outputs ***
313	  IrqOut    <= r.Irq;
314	  PostTrig  <= r.Reg_PostTrig;
315	  Arm       <= r.Reg_Mode_Arm;
316	  RecMode   <= r.Reg_Mode_Recm;
317	  ToDisable <= r.Reg_Mode_ToDisable;
318	  FrameTo   <= r.Reg_Mode_FrameTo;
319	  ARProt    <= r.Reg_AcpCfg_ARProt;
320	  ARCache   <= r.Reg_AcpCfg_ARCache;
321	  AWProt    <= r.Reg_AcpCfg_AWProt;
322	  AWCache   <= r.Reg_AcpCfg_AWCache;
323	
324	  --------------------------------------------
325	  -- Sequential Process
326	  --------------------------------------------
327	  p_seq : process(S_Axi_Aclk)
328	  begin
329	    if rising_edge(S_Axi_Aclk) then
330	      r <= r_next;
331	      if A_Axi_Areset = '1' then
332	        r.Reg_Gcfg_Ena       <= '0';
333	        r.Reg_Gcfg_IrqEna    <= '0';
334	        r.Reg_IrqVec         <= (others => '0');
335	        r.Reg_IrqEna         <= (others => '0');
336	        r.Reg_StrEna         <= (others => '0');
337	        r.Reg_AcpCfg_ARProt  <= (others => '0');
338	        r.Reg_AcpCfg_ARCache <= (others => '0');
339	        r.Reg_AcpCfg_AWProt  <= (others => '0');
340	        r.Reg_AcpCfg_AWCache <= (others => '0');
341	        r.Irq                <= '0';
342	        r.Reg_PostTrig       <= (others => (others => '0'));
343	        r.Reg_Mode_Recm      <= (others => (others => '0'));
344	        r.Reg_Mode_Arm       <= (others => '0');
345	        r.Reg_Mode_ToDisable <= (others => '0');
346	        r.Reg_Mode_FrameTo   <= (others => '0');
347	      end if;
348	    end if;
349	  end process;
350	
351	  --------------------------------------------
352	  -- Maximum Level Latching (MemClk)
353	  --------------------------------------------
354	  p_maxlvl : process(ClkMem)
355	  begin
356	    if rising_edge(ClkMem) then
357	      if RstMem = '1' then
358	        MaxLevel <= (others => (others => '0'));
359	      else
360	        -- Latch maximum level
361	        for i in 0 to Streams_g - 1 loop
362	          if MaxLevelClr_Sync(i) = '1' then
363	            MaxLevel(i) <= (others => '0');
364	          elsif unsigned(InLevel(i)) > unsigned(MaxLevel(i)) then
365	            MaxLevel(i) <= InLevel(i);
366	          end if;
367	        end loop;
368	      end if;
369	    end if;
370	  end process;
371	
372	  --------------------------------------------
373	  -- Component Instantiations
374	  --------------------------------------------
375	
376	  -- *** AXI Interface ***
377	  i_axi : entity work.psi_common_axi_slave_ipif
378	    generic map(
379	      num_reg_g        => 16,
380	      rst_val_g        => (0  => (others => '0'), 1 => (others => '0'), 2 => (others => '0'), 3 => (others => '0'),
381	                           4  => (others => '0'), 5 => (others => '0'), 6 => (others => '0'), 7 => (others => '0'),
382	                           8  => (others => '0'), 9 => (others => '0'), 10 => (others => '0'), 11 => (others => '0'),
383	                           12 => (others => '0'), 13 => (others => '0'), 14 => (others => '0'), 15 => (others => '0')),
384	      use_mem_g        => true,
385	      axi_id_width_g   => AxiSlaveIdWidth_g,
386	      axi_addr_width_g => 16
387	    )
388	    port map(
389	      s_axi_aclk    => S_Axi_Aclk,
390	      s_axi_aresetn => S_Axi_Aresetn,
391	      s_axi_arid    => S_Axi_ArId,
392	      s_axi_araddr  => S_Axi_ArAddr,
393	      s_axi_arlen   => S_Axi_Arlen,
394	      s_axi_arsize  => S_Axi_ArSize,
395	      s_axi_arburst => S_Axi_ArBurst,
396	      s_axi_arlock  => S_Axi_ArLock,
397	      s_axi_arcache => S_Axi_ArCache,
398	      s_axi_arprot  => S_Axi_ArProt,
399	      s_axi_arvalid => S_Axi_ArValid,
400	      s_axi_arready => S_Axi_ArReady,
401	      s_axi_rid     => S_Axi_RId,
402	      s_axi_rdata   => S_Axi_RData,
403	      s_axi_rresp   => S_Axi_RResp,
404	      s_axi_rlast   => S_Axi_RLast,
405	      s_axi_rvalid  => S_Axi_RValid,
406	      s_axi_rready  => S_Axi_RReady,
407	      s_axi_awid    => S_Axi_AwId,
408	      s_axi_awaddr  => S_Axi_AwAddr,
409	      s_axi_awlen   => S_Axi_AwLen,
410	      s_axi_awsize  => S_Axi_AwSize,
411	      s_axi_awburst => S_Axi_AwBurst,
412	      s_axi_awlock  => S_Axi_AwLock,
413	      s_axi_awcache => S_Axi_AwCache,
414	      s_axi_awprot  => S_Axi_AwProt,
415	      s_axi_awvalid => S_Axi_AwValid,
416	      s_axi_awready => S_Axi_AwReady,
417	      s_axi_wdata   => S_Axi_WData,
418	      s_axi_wstrb   => S_Axi_WStrb,
419	      s_axi_wlast   => S_Axi_WLast,
420	      s_axi_wvalid  => S_Axi_WValid,
421	      s_axi_wready  => S_Axi_WReady,
422	      s_axi_bid     => S_Axi_BId,
423	      s_axi_bresp   => S_Axi_BResp,
424	      s_axi_bvalid  => S_Axi_BValid,
425	      s_axi_bready  => S_Axi_BReady,
426	      o_reg_rd      => open,
427	      i_reg_rdata   => RegRdVal,
428	      o_reg_wr      => RegWr,
429	      o_reg_wdata   => RegWrVal,
430	      o_mem_addr    => AccAddrOffs,
431	      o_mem_wr      => AccWr,
432	      o_mem_wdata   => AccWrData,
433	      i_mem_rdata   => AccRdData
434	    );
435	
436	  AccAddr <= std_logic_vector(unsigned(AccAddrOffs) + 16 * 4);
437	
438	  -- *** Clock Crossings ***
439	  blk_cc_irq : block
440	  begin
441	    g_in : for i in 0 to Streams_g - 1 generate
442	
443	      i_cc_irq : entity work.psi_common_simple_cc
444	        generic map(
445	          width_g => log2ceil(MaxWindows_c)
446	        )
447	        port map(
448	          a_clk_i => ClkMem,
449	          a_rst_i => RstMem,
450	          a_dat_i => StrLastWin(i),
451	          a_vld_i => StrIrq(i),
452	          b_clk_i => S_Axi_Aclk,
453	          b_rst_i => A_Axi_Areset,
454	          b_dat_o => StrLastWin_Sync(i),
455	          b_vld_o => StrIrq_Sync(i)
456	        );
457	    end generate;
458	  end block;
459	
460	  blk_cc_mem_out : block
461	    signal ccIn, ccOut : std_logic_vector(Streams_g downto 0);
462	  begin
463	    -- Input Assembly
464	    ccIn(Streams_g - 1 downto 0) <= r.Reg_StrEna;
465	    ccIn(Streams_g)              <= r.Reg_Gcfg_Ena;
466	
467	    -- Instantiation
468	    i_cc_mem_out : entity work.psi_common_bit_cc
469	      generic map(
470	        width_g => Streams_g + 1
471	      )
472	      port map(
473	        dat_i => ccIn,
474	        clk_i => ClkMem,
475	        dat_o => ccOut
476	      );
477	
478	    -- Output assembly
479	    StrEna <= ccOut(Streams_g - 1 downto 0);
480	    GlbEna <= ccOut(Streams_g);
481	  end block;
482	
483	  i_cc_mem_out_pulse : entity work.psi_common_pulse_cc
484	    generic map(
485	      num_pulses_g => Streams_g
486	    )
487	    port map(
488	      a_clk_i => S_Axi_Aclk,
489	      a_rst_i => A_Axi_Areset,
490	      a_dat_i => r.MaxLvlClr,
491	      b_clk_i => ClkMem,
492	      b_rst_i => RstMem,
493	      b_dat_o => MaxLevelClr_Sync
494	    );
495	
496	  -- *** Stream Context Memory ***
497	  -- Signal Assembly
498	  AddrCtxStr   <= AccAddr(15 downto 12) = X"1";
499	  CtxStr_WeLo  <= '1' when AccWr = DwWrite_c and AddrCtxStr and AccAddr(2) = '0' else '0';
500	  CtxStr_WeHi  <= '1' when AccWr = DwWrite_c and AddrCtxStr and AccAddr(2) = '1' else '0';
501	  CtxStr_AddrB <= std_logic_vector(to_unsigned(CtxStr_Cmd.Stream, log2ceil(Streams_g))) & CtxStr_Cmd.Sel;
502	
503	  -- Memory is split organized as 64 bit memory for historical reasons (Tosca TMEM is 64-bit)
504	
505	  -- Low DWORD memory
506	  i_mem_ctx_lo : entity work.psi_common_tdp_ram
507	    generic map(
508	      depth_g    => DepthCtxStr_c,
509	      width_g    => 32,
510	      behavior_g => "RBW"
511	    )
512	    port map(
513	      a_clk_i  => S_Axi_Aclk,
514	      a_addr_i => AccAddr(CtxStrAddrHigh_c downto 3),
515	      a_wr_i   => CtxStr_WeLo,
516	      a_dat_i  => AccWrData,
517	      a_dat_o  => CtxStr_Rdval(31 downto 0),
518	      b_clk_i  => ClkMem,
519	      b_addr_i => CtxStr_AddrB,
520	      b_wr_i   => CtxStr_Cmd.WenLo,
521	      b_dat_i  => CtxStr_Cmd.WdatLo,
522	      b_dat_o  => CtxStr_Resp.RdatLo
523	    );
524	
525	  -- High DWORD memory
526	  i_mem_ctx_hi : entity work.psi_common_tdp_ram
527	    generic map(
528	      depth_g    => DepthCtxStr_c,
529	      width_g    => 32,
530	      behavior_g => "RBW"
531	    )
532	    port map(
533	      a_clk_i  => S_Axi_Aclk,
534	      a_addr_i => AccAddr(CtxStrAddrHigh_c downto 3),
535	      a_wr_i   => CtxStr_WeHi,
536	      a_dat_i  => AccWrData,
537	      a_dat_o  => CtxStr_Rdval(63 downto 32),
538	      b_clk_i  => ClkMem,
539	      b_addr_i => CtxStr_AddrB,
540	      b_wr_i   => CtxStr_Cmd.WenHi,
541	      b_dat_i  => CtxStr_Cmd.WdatHi,
542	      b_dat_o  => CtxStr_Resp.RdatHi
543	    );
544	
545	  -- *** Window Context Memory ***
546	  -- Signal Assembly
547	  AddrCtxWin   <= AccAddr(15 downto 14) = "01";
548	  CtxWin_WeLo  <= '1' when AccWr = DwWrite_c and AddrCtxWin and AccAddr(2) = '0' else '0';
549	  CtxWin_WeHi  <= '1' when AccWr = DwWrite_c and AddrCtxWin and AccAddr(2) = '1' else '0';
550	  CtxWin_AddrB <= std_logic_vector(to_unsigned(CtxWin_Cmd.Stream, log2ceil(Streams_g))) & std_logic_vector(to_unsigned(CtxWin_Cmd.Window, log2ceil(MaxWindows_g))) & CtxWin_Cmd.Sel;
551	
552	  -- Memory is split organized as 64 bit memory for historical reasons (Tosca TMEM is 64-bit)
553	
554	  -- Low DWORD memory
555	  i_mem_win_lo : entity work.psi_common_tdp_ram
556	    generic map(
557	      depth_g    => DepthCtxWin_c,
558	      width_g    => 32,
559	      behavior_g => "RBW"
560	    )
561	    port map(
562	      a_clk_i  => S_Axi_Aclk,
563	      a_addr_i => AccAddr(CtxWinAddrHigh_c downto 3),
564	      a_wr_i   => CtxWin_WeLo,
565	      a_dat_i  => AccWrData,
566	      a_dat_o  => CtxWin_Rdval(31 downto 0),
567	      b_clk_i  => ClkMem,
568	      b_addr_i => CtxWin_AddrB,
569	      b_wr_i   => CtxWin_Cmd.WenLo,
570	      b_dat_i  => CtxWin_Cmd.WdatLo,
571	      b_dat_o  => CtxWin_Resp.RdatLo
572	    );
573	
574	  -- High DWORD memory
575	  i_mem_win_hi : entity work.psi_common_tdp_ram
576	    generic map(
577	      depth_g    => DepthCtxWin_c,
578	      width_g    => 32,
579	      behavior_g => "RBW"
580	    )
581	    port map(
582	      a_clk_i  => S_Axi_Aclk,
583	      a_addr_i => AccAddr(CtxWinAddrHigh_c downto 3),
584	      a_wr_i   => CtxWin_WeHi,
585	      a_dat_i  => AccWrData,
586	      a_dat_o  => CtxWin_Rdval(63 downto 32),
587	      b_clk_i  => ClkMem,
588	      b_addr_i => CtxWin_AddrB,
589	      b_wr_i   => CtxWin_Cmd.WenHi,
590	      b_dat_i  => CtxWin_Cmd.WdatHi,
591	      b_dat_o  => CtxWin_Resp.RdatHi
592	    );
593	
594	end architecture;
595

